import zipfile
import tarfile
import os

def create_archive(source_paths, output_archive_path):
    if not isinstance(source_paths, list):
        raise TypeError("source_paths must be a list.")
    if not source_paths:
        raise ValueError("source_paths cannot be empty.")

    output_archive_path = os.path.abspath(output_archive_path)
    archive_format = None
    if output_archive_path.endswith('.zip'):
        archive_format = 'zip'
    elif output_archive_path.endswith(('.tar.gz', '.tgz')):
        archive_format = 'tar.gz'
    elif output_archive_path.endswith(('.tar.bz2', '.tbz2')):
        archive_format = 'tar.bz2'
    elif output_archive_path.endswith(('.tar.xz', '.txz')):
        archive_format = 'tar.xz'
    elif output_archive_path.endswith('.tar'):
        archive_format = 'tar'
    else:
        raise ValueError("Unsupported archive format extension. Supported: .zip, .tar, .tar.gz, .tar.bz2, .tar.xz")

    if archive_format == 'zip':
        with zipfile.ZipFile(output_archive_path, 'w', zipfile.ZIP_DEFLATED) as zipf:
            for path in source_paths:
                abs_path = os.path.abspath(path)
                if not os.path.exists(abs_path):
                    continue

                if os.path.isfile(abs_path):
                    zipf.write(abs_path, os.path.basename(abs_path))
                elif os.path.isdir(abs_path):
                    for root, _, files in os.walk(abs_path):
                        for file in files:
                            file_path = os.path.join(root, file)
                            arcname = os.path.join(os.path.basename(abs_path), os.path.relpath(file_path, abs_path))
                            zipf.write(file_path, arcname)
    elif archive_format.startswith('tar'):
        mode = 'w'
        if archive_format == 'tar.gz':
            mode = 'w:gz'
        elif archive_format == 'tar.bz2':
            mode = 'w:bz2'
        elif archive_format == 'tar.xz':
            mode = 'w:xz'

        with tarfile.open(output_archive_path, mode) as tarf:
            for path in source_paths:
                abs_path = os.path.abspath(path)
                if not os.path.exists(abs_path):
                    continue

                tarf.add(abs_path, arcname=os.path.basename(abs_path))
